import json
counts = {'INFO': 0, 'WARN': 0, 'ERROR': 0}
with open('log.txt') as f:
    for line in f:
        for prefix in counts:
            if line.startswith(prefix):
                counts[prefix] += 1
with open('counts.json', 'w') as f:
    json.dump(counts, f, indent=2)
